   115→  values(): number[] {
   116→    return this.data.map((d) => d.v);
   117→  }
   118→
   119→  size(): number {
   120→    return this.data.length;
   121→  }
   122→
   123→  /**
   124→   * Removes samples that fall outside of the window.
   125→   */
   126→  private trim(currentTime: number) {
   127→    const threshold = currentTime - this.windowMillis;
