   137→//#region ────────────────────────────────  Strategy – correlation  ───────────────────────────────
   138→
   139→export interface CorrelationStrategy {
   140→  /**
   141→   * Computes correlation coefficient between series X and Y.
   142→   *
   143→   * Both arrays must be of equal length & >0
   144→   */
