    86→
    87→  compute(baseThreshold: number, event: SocialMetricEvent): number {
    88→    // Simple heuristic: amplify threshold when delta exceeds 1k events/second.
    89→    if (event.delta > 1_000) {
    90→      const boosted = baseThreshold * this.boostFactor;
    91→      logger.debug(`TrendingBoostStrategy applied: ${baseThreshold} -> ${boosted}`);
    92→      return boosted;
    93→    }
    94→    return baseThreshold;
    95→  }
