   101→export class NightTimeRelaxStrategy implements ThresholdStrategy {
   102→  constructor(private readonly relaxFactor = 0.8) {}
   103→
   104→  private isNightHour(utcMillis: number): boolean {
   105→    const hour = new Date(utcMillis).getUTCHours();
   106→    return hour >= 0 && hour <= 6; // midnight – 6 AM UTC
