     2→/****************************************************************************************
     3→ *  PulseSphere SocialOps – System Monitoring Platform
     4→ *  --------------------------------------------------
     5→ *  File:        src/module_4.ts
     6→ *  Description: Alert-correlation engine that marries infrastructure telemetry with
     7→ *               social-engagement signals. Implements the Strategy pattern so that
     8→ *               SRE teams can hot-swap correlation algorithms at runtime (via dynamic
     9→ *               configuration pushed through the platform’s configuration-management
    10→ *               microservice).
    11→ *
    12→ *  Key Patterns:
    13→ *      • Strategy Pattern      – Pluggable correlation algorithms
    14→ *      • Observer (RxJS)       – Stream/buffer telemetry events
    15→ *      • Command Pattern       – Publishes alert commands to message bus
    16→ *      • Error-handling        – Fault-tolerant, production-grade
    17→ *
    18→ *  Author:      PulseSphere Core Engineering
    19→ ****************************************************************************************/
    20→
    21→import { Subject, Observable, bufferTime, filter, map } from 'rxjs';
    22→import { v4 as uuidv4 } from 'uuid';
    23→import dayjs from 'dayjs';
    24→
    25→/* -------------------------------------------------------------------------- */
    26→/*                                Domain Types                                */
    27→/* -------------------------------------------------------------------------- */
    28→
    29→/** Social context that accompanies every telemetry datapoint */
    30→export interface SocialContext {
    31→  likes: number;
    32→  comments: number;
    33→  shares: number;
    34→  liveStreamViewers: number;
    35→  trendingHashtags?: string[];
    36→}
    37→
    38→/** Raw telemetry emitted by lower-level collectors */
    39→export interface TelemetryEvent {
    40→  readonly id: string;               // Unique identifier for the metric datapoint
    41→  readonly metric: string;           // e.g. cpu.utilization, api.latency
    42→  readonly value: number;
    43→  readonly timestamp: number;        // epoch-ms
    44→  readonly tags?: Record<string, string>;
    45→  readonly social: SocialContext;    // Social dimension
    46→}
    47→
    48→/** Correlated alert dispatched to downstream Alerting-MS */
    49→export interface Alert {
    50→  readonly id: string;
    51→  readonly severity: 'INFO' | 'WARN' | 'CRITICAL';
    52→  readonly title: string;
    53→  readonly description: string;
    54→  readonly createdAt: number;
    55→  readonly correlatedEvents: string[]; // list of TelemetryEvent.id
