    57→
    58→/* -------------------------------------------------------------------------- */
    59→/*                     Infrastructure / Adapter Layer (Ports)                 */
    60→/* -------------------------------------------------------------------------- */
    61→
    62→/**
    63→ * Simplified interface for the platform’s configuration service.
    64→ * It supports live-reloading and notifies subscribers on updates.
    65→ */
    66→export interface ConfigurationService {
    67→  get<T = unknown>(path: string): T;
    68→  onChange(path: string): Observable<unknown>;
