    78→
    79→/* -------------------------------------------------------------------------- */
    80→/*                       Correlation Strategy – Abstraction                   */
    81→/* -------------------------------------------------------------------------- */
    82→
    83→/**
    84→ * Strategy pattern for correlation. Each implementation analyses the buffered
    85→ * telemetry events and decides if/when an Alert must be raised.
    86→ */
    87→export interface AlertCorrelationStrategy {
    88→  /**
    89→   * Analyses a batch (time-window) of telemetry events and emits zero or more Alerts.
    90→   * @param events  – All telemetry events gathered within the window
    91→   */
    92→  correlate(events: ReadonlyArray<TelemetryEvent>): Alert[];
