    94→
    95→/* -------------------------------------------------------------------------- */
    96→/*           Concrete Strategies – Used by AlertCorrelationEngine             */
    97→/* -------------------------------------------------------------------------- */
    98→
    99→/**
   100→ * Simple threshold-based strategy. Demonstrates how social amplification
   101→ * (likes/shares) can raise severity.
   102→ */
   103→export class ThresholdStrategy implements AlertCorrelationStrategy {
   104→  private readonly cpuThreshold: number;
   105→  private readonly socialAmplificationFactor: number;
   106→
   107→  constructor(options: { cpuThreshold: number; amplificationFactor: number }) {
   108→    this.cpuThreshold = options.cpuThreshold;
