   147→export class TrendingHashtagStrategy implements AlertCorrelationStrategy {
   148→  private readonly latencyP99ThresholdMs: number;
   149→  private readonly hashtagSurgeThreshold: number;
   150→
   151→  constructor(opts: { latencyP99ThresholdMs: number; hashtagSurgeThreshold: number }) {
