   165→    const hasLatencyIssue = latencyEvents.some((e) => e.value >= this.latencyP99ThresholdMs);
   166→    const trendingScore =
   167→      trendingEvents.reduce(
   168→        (acc, ev) => acc + (ev.social.trendingHashtags?.length ?? 0),
   169→        0
   170→      ) / Math.max(trendingEvents.length, 1);
   171→
   172→    if (hasLatencyIssue && trendingScore >= this.hashtagSurgeThreshold) {
   173→      const correlatedIds = [...latencyEvents, ...trendingEvents].map((e) => e.id);
   174→
   175→      alerts.push({
   176→        id: uuidv4(),
   177→        severity: 'CRITICAL',
   178→        title: 'Latency spike during trending hashtag surge',
   179→        description: `P99 latency exceeded ${
   180→          this.latencyP99ThresholdMs
   181→        }ms while trending activity score=${trendingScore.toFixed(
   182→          2
