     2→/**************************************************************************************************
     3→ *  PulseSphere SocialOps – System Monitoring
     4→ *  ------------------------------------------------------------
     5→ *  File:        src/module_1.ts
     6→ *  Description: Telemetry enrichment & adaptive-scaling pipeline that demonstrates several of
     7→ *               PulseSphere’s architectural patterns in a single, self-contained module:
     8→ *
     9→ *                 • Observer pattern     – EventEmitter-based telemetry bus
    10→ *                 • Strategy pattern     – Pluggable social-influence scoring & scaling decisions
    11→ *                 • Chain of Responsibility – Hierarchical scaling-decision evaluators
    12→ *                 • Command pattern      – Encapsulated, auditable remediation commands
    13→ *
    14→ *               Although this is a single file, it is written as production-quality code that
    15→ *               could be dropped into one of the 88 services that make up PulseSphere.
    16→ *
    17→ *  Notes:
    18→ *    – No external runtime dependencies besides Node’s stdlib & `pino` for structured logging.
    19→ *    – Source-maps, strict-null, etc. are assumed to be enabled in tsconfig.
    20→ **************************************************************************************************/
    21→
    22→import { EventEmitter } from 'events';
    23→import { randomUUID } from 'crypto';
    24→import pino from 'pino';
    25→
    26→/* -------------------------------------------------------------------------------------------------
    27→ * Logger – Using pino for minimal overhead structured logging
    28→ * -----------------------------------------------------------------------------------------------*/
    29→const logger = pino({
    30→    name: 'adaptive-scaler',
    31→    level: process.env.LOG_LEVEL ?? 'info',
    32→});
    33→
    34→/* -------------------------------------------------------------------------------------------------
    35→ * Domain Models
    36→ * -----------------------------------------------------------------------------------------------*/
    37→
    38→/** Raw infra-metric produced by Prometheus or an agent */
    39→export interface RawMetric {
    40→    readonly service: string;
    41→    readonly timestamp: number;           // Unix epoch (ms)
    42→    readonly cpu: number;                 // %
    43→    readonly memory: number;              // %
    44→    readonly requestPerSecond: number;
    45→}
    46→
    47→/** Social engagement signal produced by PulseSphere’s social ingestion service */
    48→export interface SocialSignal {
    49→    readonly hashtag: string;
    50→    readonly likes: number;
    51→    readonly comments: number;
    52→    readonly shares: number;
    53→    readonly timestamp: number;           // Unix epoch (ms)
    54→}
    55→
    56→/** Metric that has been enriched with social context */
    57→export interface EnrichedMetric extends RawMetric {
    58→    readonly socialInfluenceScore: number; // 0-1000 (arbitrary scale)
    59→}
    60→
    61→/** Possible scaling actions */
    62→export enum ScaleAction {
    63→    ScaleOut  = 'SCALE_OUT',
    64→    ScaleIn   = 'SCALE_IN',
    65→    None      = 'NONE',
    66→}
    67→
    68→/** A remediation / scaling decision */
    69→export interface ScalingDecision {
    70→    readonly id: string;
    71→    readonly service: string;
    72→    readonly action: ScaleAction;
    73→    readonly proposedCapacity: number;   // Desired replica count / capacity unit
    74→    readonly reason: string;
    75→    readonly decidedAt: number;
    76→}
    77→
    78→/* -------------------------------------------------------------------------------------------------
    79→ * Observer Pattern – Telemetry Bus
    80→ * -----------------------------------------------------------------------------------------------*/
    81→
    82→/**
    83→ * TelemetryBus acts as the Subject (EventEmitter) in the Observer pattern.
    84→ * Components may subscribe to:
    85→ *   – 'rawMetric'
    86→ *   – 'socialSignal'
    87→ *   – 'enrichedMetric'
    88→ */
    89→export class TelemetryBus extends EventEmitter {
    90→    private static _instance: TelemetryBus;
    91→
    92→    private constructor() { super(); }
    93→
    94→    public static instance(): TelemetryBus {
    95→        if (!TelemetryBus._instance) {
    96→            TelemetryBus._instance = new TelemetryBus();
    97→        }
    98→        return TelemetryBus._instance;
    99→    }
   100→}
   101→
   102→/* -------------------------------------------------------------------------------------------------
   103→ * Strategy Pattern – Social Influence Scoring
   104→ * -----------------------------------------------------------------------------------------------*/
   105→
   106→/** Calculates an influence score from a social signal */
   107→export interface InfluenceScoringStrategy {
   108→    computeScore(signal: SocialSignal): number;
   109→}
   110→
   111→/**
   112→ * Simple baseline strategy that weights likes/comments/shares.
   113→ * Can be replaced at runtime with an ML-based implementation.
   114→ */
   115→export class EngagementWeightedScoreStrategy implements InfluenceScoringStrategy {
   116→    private readonly likeWeight = 1;
   117→    private readonly commentWeight = 2;
   118→    private readonly shareWeight = 3;
   119→
   120→    computeScore(signal: SocialSignal): number {
   121→        const score = (
   122→            (signal.likes   * this.likeWeight) +
   123→            (signal.comments * this.commentWeight) +
   124→            (signal.shares  * this.shareWeight)
   125→        );
   126→
   127→        logger.debug({ score, signal }, 'Computed social influence score');
   128→        return score;
   129→    }
   130→}
   131→
   132→/* -------------------------------------------------------------------------------------------------
   133→ * Strategy Pattern – Scaling decisions
   134→ * -----------------------------------------------------------------------------------------------*/
   135→
   136→export interface ScalingStrategy {
   137→    decide(metric: EnrichedMetric): ScalingDecision | null;
   138→}
   139→
   140→/**
   141→ * CPU-heavy strategy – scale out when CPU > 80%, scale in when < 30%
   142→ */
   143→export class CpuThresholdScalingStrategy implements ScalingStrategy {
   144→    private static readonly UPSCALE_THRESHOLD = 0.80;
   145→    private static readonly DOWNSCALE_THRESHOLD = 0.30;
   146→
   147→    decide(metric: EnrichedMetric): ScalingDecision | null {
   148→        const { cpu, service } = metric;
   149→
   150→        if (cpu > CpuThresholdScalingStrategy.UPSCALE_THRESHOLD) {
   151→            return this.buildDecision(service, ScaleAction.ScaleOut,
   152→                `CPU ${cpu * 100}% > ${CpuThresholdScalingStrategy.UPSCALE_THRESHOLD * 100}%`);
   153→        }
   154→
   155→        if (cpu < CpuThresholdScalingStrategy.DOWNSCALE_THRESHOLD) {
   156→            return this.buildDecision(service, ScaleAction.ScaleIn,
   157→                `CPU ${cpu * 100}% < ${CpuThresholdScalingStrategy.DOWNSCALE_THRESHOLD * 100}%`);
   158→        }
   159→
   160→        return null;
   161→    }
   162→
   163→    private buildDecision(service: string, action: ScaleAction, reason: string): ScalingDecision {
   164→        return {
   165→            id: randomUUID(),
   166→            service,
   167→            action,
   168→            decidedAt: Date.now(),
   169→            proposedCapacity: action === ScaleAction.ScaleOut ? 2 : -1, // simplistic delta
   170→            reason,
   171→        };
   172→    }
   173→}
   174→
   175→/**
   176→ * Virality-aware strategy – uses social influence to anticipate load spikes
   177→ */
   178→export class ViralityScalingStrategy implements ScalingStrategy {
   179→    private static readonly VIRALITY_THRESHOLD = 500; // arbitrary scale
   180→
   181→    decide(metric: EnrichedMetric): ScalingDecision | null {
   182→        const { socialInfluenceScore, service } = metric;
   183→
   184→        if (socialInfluenceScore >= ViralityScalingStrategy.VIRALITY_THRESHOLD) {
   185→            return {
   186→                id: randomUUID(),
   187→                service,
   188→                action: ScaleAction.ScaleOut,
   189→                proposedCapacity: 3, // aggressively over-provision
   190→                reason: `Social virality score (${socialInfluenceScore}) exceeds threshold`,
   191→                decidedAt: Date.now(),
   192→            };
   193→        }
   194→
   195→        return null;
   196→    }
   197→}
   198→
   199→/* -------------------------------------------------------------------------------------------------
   200→ * Chain of Responsibility – Compose multiple scaling strategies
   201→ * -----------------------------------------------------------------------------------------------*/
   202→
   203→abstract class ScalingHandler {
   204→    private next: ScalingHandler | null = null;
   205→
   206→    public setNext(handler: ScalingHandler): this {
   207→        this.next = handler;
   208→        return handler;
   209→    }
   210→
   211→    public handle(metric: EnrichedMetric): ScalingDecision | null {
   212→        const decision = this.process(metric);
   213→
   214→        if (decision) {
   215→            logger.info({ decision }, 'ScalingHandler produced decision');
   216→            return decision;
   217→        }
   218→
   219→        if (this.next) {
   220→            return this.next.handle(metric);
   221→        }
   222→
   223→        logger.debug('No scaling handler produced a decision');
   224→        return null;
   225→    }
   226→
   227→    protected abstract process(metric: EnrichedMetric): ScalingDecision | null;
   228→}
   229→
   230→class CpuHandler extends ScalingHandler {
   231→    private readonly strategy = new CpuThresholdScalingStrategy();
   232→
   233→    protected process(metric: EnrichedMetric): ScalingDecision | null {
   234→        return this.strategy.decide(metric);
   235→    }
   236→}
   237→
   238→class ViralityHandler extends ScalingHandler {
   239→    private readonly strategy = new ViralityScalingStrategy();
   240→
   241→    protected process(metric: EnrichedMetric): ScalingDecision | null {
   242→        return this.strategy.decide(metric);
   243→    }
   244→}
   245→
   246→/* -------------------------------------------------------------------------------------------------
   247→ * Command Pattern – Executable remediation commands
   248→ * -----------------------------------------------------------------------------------------------*/
   249→
   250→export interface Command {
   251→    readonly id: string;
   252→    readonly createdAt: number;
   253→    execute(): Promise<void>;
   254→}
   255→
   256→export class ScaleCommand implements Command {
   257→    public readonly id = randomUUID();
   258→    public readonly createdAt = Date.now();
   259→
   260→    constructor(private readonly decision: ScalingDecision) {}
   261→
   262→    async execute(): Promise<void> {
   263→        try {
   264→            logger.info({ decision: this.decision }, 'Executing scale command');
   265→
   266→            // Placeholder for real orchestration call:
   267→            // await kubernetesClient.scaleDeployment(this.decision.service, this.decision.proposedCapacity);
   268→            await this.mockApiCall();
   269→
   270→            logger.info({ decisionId: this.decision.id }, 'Scale command executed successfully');
   271→        } catch (err) {
   272→            logger.error({ err, decisionId: this.decision.id }, 'Failed to execute scale command');
   273→            throw err;
   274→        }
   275→    }
   276→
   277→    // Simulate network delay / response
   278→    private async mockApiCall(): Promise<void> {
   279→        return new Promise((resolve) => setTimeout(resolve, 300));
   280→    }
   281→}
   282→
   283→/* -------------------------------------------------------------------------------------------------
   284→ * Enrichment Processor (Observer of rawMetric & socialSignal)
   285→ * -----------------------------------------------------------------------------------------------*/
   286→
   287→export class EnrichmentProcessor {
   288→    private readonly scoringStrategy: InfluenceScoringStrategy;
   289→    private readonly bus = TelemetryBus.instance();
   290→
   291→    // Keep last social signal timestamp per hashtag to correlate quickly
   292→    private latestSocialSignal: Map<string, SocialSignal> = new Map();
   293→
   294→    constructor(scoringStrategy: InfluenceScoringStrategy = new EngagementWeightedScoreStrategy()) {
   295→        this.scoringStrategy = scoringStrategy;
   296→    }
   297→
   298→    start(): void {
   299→        this.bus.on('rawMetric', (metric: RawMetric) => this.handleMetric(metric));
   300→        this.bus.on('socialSignal', (signal: SocialSignal) => this.cacheSocialSignal(signal));
   301→    }
   302→
   303→    private cacheSocialSignal(signal: SocialSignal): void {
   304→        this.latestSocialSignal.set(signal.hashtag, signal);
   305→        logger.debug({ signal }, 'Cached social signal');
   306→    }
   307→
   308→    private handleMetric(metric: RawMetric): void {
   309→        try {
   310→            const socialSignal = this.latestSocialSignal.get(`#${metric.service}`); // service-level hashtag convention
   311→            const socialInfluenceScore = socialSignal
   312→                ? this.scoringStrategy.computeScore(socialSignal)
   313→                : 0;
   314→
   315→            const enriched: EnrichedMetric = { ...metric, socialInfluenceScore };
   316→
   317→            logger.debug({ enriched }, 'Publishing enriched metric');
   318→            this.bus.emit('enrichedMetric', enriched);
   319→        } catch (err) {
   320→            logger.error({ err, metric }, 'Failed to enrich metric');
   321→        }
   322→    }
   323→}
   324→
   325→/* -------------------------------------------------------------------------------------------------
   326→ * AdaptiveScaler – ties everything together
   327→ * -----------------------------------------------------------------------------------------------*/
   328→
   329→export class AdaptiveScaler {
   330→    private readonly bus = TelemetryBus.instance();
   331→    private readonly decisionHandler: ScalingHandler;
   332→    private isRunning = false;
   333→
   334→    constructor() {
   335→        // Build Chain of Responsibility: ViralityHandler -> CpuHandler
   336→        const virality = new ViralityHandler();
   337→        const cpu       = new CpuHandler();
   338→        virality.setNext(cpu);
   339→
   340→        this.decisionHandler = virality;
   341→    }
   342→
   343→    public start(): void {
   344→        if (this.isRunning) return;
   345→        this.isRunning = true;
   346→
   347→        this.bus.on('enrichedMetric', (metric: EnrichedMetric) => this.handleEnrichedMetric(metric));
   348→
   349→        logger.info('AdaptiveScaler started');
   350→    }
   351→
   352→    private async handleEnrichedMetric(metric: EnrichedMetric): Promise<void> {
   353→        const decision = this.decisionHandler.handle(metric);
   354→
   355→        if (!decision || decision.action === ScaleAction.None) return;
   356→
   357→        const cmd = new ScaleCommand(decision);
   358→        try {
   359→            await cmd.execute();
   360→        } catch {
   361→            // Errors already logged inside command
   362→        }
   363→    }
