    33→
    34→/* ------------------------------------------------------------------ */
    35→/*                                Types                               */
    36→/* ------------------------------------------------------------------ */
    37→
    38→/**
    39→ * Raw, enriched telemetry event.
    40→ */
    41→export interface MetricEvent {
    42→  service: string; // e.g. "timeline-api"
    43→  host: string; // e.g. "ip-10-2-3-4"
    44→  timestamp: number; // epoch millis
    45→  metrics: {
