    88→
    89→/**
    90→ * CPU Spike strategy – identifies sudden CPU utilisation > 85%.
    91→ */
    92→export class CpuSpikeStrategy implements DetectionStrategy {
    93→  readonly name = 'cpu_spike';
    94→
    95→  detect(event: MetricEvent): DetectionResult | null {
    96→    const { cpuUtilization } = event.metrics;
    97→    if (cpuUtilization > 0.85) {
    98→      return {
    99→        isAnomaly: true,
   100→        severity: cpuUtilization > 0.95 ? Severity.Critical : Severity.High,
   101→        reason: `CPU utilisation at ${(cpuUtilization * 100).toFixed(2)}%`,
   102→        strategy: this.name,
   103→      };
   104→    }
   105→    return null;
   106→  }
   107→}
   108→
   109→/**
