     2→/**
     3→ * PulseSphere SocialOps
     4→ * -------------------------------------------------------
     5→ * Module: module_17 – Social-Aware Auto-Scaler & Alerting
     6→ *
     7→ * This module wires together multiple classic patterns to
     8→ * provide a production-grade, socially-aware auto-scaling
     9→ * component.
    10→ *
    11→ * Patterns in use
    12→ *  • Observer            – MetricEventBus (EventEmitter)
    13→ *  • Strategy            – ScalingStrategy implementations
    14→ *  • Command             – Scale{Up,Down}Command
    15→ *  • Chain-of-Responsibility – AlertHandler chain
    16→ *  • Event Driven        – Kafka consumer feeding the bus
    17→ *
    18→ * External deps
    19→ *  • kafkajs             – High-throughput metric ingestion
    20→ *  • axios               – Mock service-mesh HTTP client
    21→ *
    22→ * Author:  PulseSphere SRE Platform Team
    23→ * -------------------------------------------------------
    24→ */
    25→
    26→import { EventEmitter } from 'events';
    27→import { Kafka, EachMessagePayload, logLevel as KafkaLogLevel } from 'kafkajs';
    28→import axios, { AxiosInstance } from 'axios';
    29→
    30→/* -------------------------------------------------------------------------- */
    31→/*                               Static typings                               */
    32→/* -------------------------------------------------------------------------- */
    33→
    34→/** A single enriched metric coming from pulse-fusion pipeline. */
    35→export interface EnrichedMetric {
    36→  readonly appId: string;
    37→  readonly cpuPct: number;               // 0-100
    38→  readonly memPct: number;               // 0-100
    39→  readonly sentimentScore: number;       // –1 .. +1
    40→  readonly trendingScore: number;        // 0 .. 1 (probability of virality)
    41→  readonly timestamp: number;            // epoch ms
    42→}
    43→
    44→export enum ScalingDecision {
    45→  SCALE_UP   = 'SCALE_UP',
    46→  SCALE_DOWN = 'SCALE_DOWN',
    47→  STABLE     = 'STABLE',
    48→}
    49→
    50→/* -------------------------------------------------------------------------- */
    51→/*                               Observer Layer                               */
    52→/* -------------------------------------------------------------------------- */
    53→
    54→/**
    55→ * Central in-process event bus – translates Kafka messages into local events
    56→ * that strategies/handlers can subscribe to without needing Kafka semantics.
    57→ */
    58→class MetricEventBus extends EventEmitter {
    59→  static readonly EVT_METRIC = 'metric';
    60→
    61→  emitMetric(metric: EnrichedMetric): void {
    62→    this.emit(MetricEventBus.EVT_METRIC, metric);
    63→  }
    64→
    65→  onMetric(listener: (metric: EnrichedMetric) => void): void {
    66→    this.on(MetricEventBus.EVT_METRIC, listener);
    67→  }
    68→}
    69→
    70→/* -------------------------------------------------------------------------- */
    71→/*                           Strategy & Command Layer                         */
    72→/* -------------------------------------------------------------------------- */
    73→
    74→/** Scaling command contract (Command Pattern). */
    75→interface ScalingCommand {
    76→  execute(): Promise<void>;
    77→}
    78→
    79→/** Concrete command – scale up by N replicas. */
    80→class ScaleUpCommand implements ScalingCommand {
    81→  constructor(
    82→    private readonly meshClient: ServiceMeshClient,
    83→    private readonly appId: string,
    84→    private readonly factor: number,
    85→  ) {}
    86→
    87→  public async execute(): Promise<void> {
    88→    await this.meshClient.scale(this.appId, this.factor);
    89→  }
    90→}
    91→
    92→/** Concrete command – scale down by N replicas. */
    93→class ScaleDownCommand implements ScalingCommand {
    94→  constructor(
    95→    private readonly meshClient: ServiceMeshClient,
    96→    private readonly appId: string,
    97→    private readonly factor: number,
    98→  ) {}
    99→
   100→  public async execute(): Promise<void> {
   101→    await this.meshClient.scale(this.appId, -this.factor);
   102→  }
   103→}
   104→
   105→/** Strategy contract – returns a Command or undefined when no action. */
   106→interface ScalingStrategy {
   107→  evaluate(metric: EnrichedMetric): ScalingCommand | undefined;
   108→}
   109→
   110→/**
   111→ * CPU-centric strategy – reacts when usage is beyond a threshold.
   112→ * This is a simplistic threshold-based algorithm; production code
   113→ * would rely on predictive analytics or RL models.
   114→ */
   115→class HighCpuStrategy implements ScalingStrategy {
   116→  constructor(
   117→    private readonly meshClient: ServiceMeshClient,
   118→    private readonly highWaterMarkPct = 75,
   119→    private readonly lowWaterMarkPct  = 35,
   120→  ) {}
   121→
   122→  evaluate(metric: EnrichedMetric): ScalingCommand | undefined {
   123→    if (metric.cpuPct >= this.highWaterMarkPct) {
   124→      const factor = Math.max(1, Math.ceil(metric.cpuPct / 25));
   125→      return new ScaleUpCommand(this.meshClient, metric.appId, factor);
   126→    }
   127→    if (metric.cpuPct <= this.lowWaterMarkPct) {
   128→      return new ScaleDownCommand(this.meshClient, metric.appId, 1);
   129→    }
   130→    return undefined;
   131→  }
   132→}
   133→
   134→/**
   135→ * Sentiment spike strategy – anticipates virality before infrastructure
   136→ * gets hammered. Combines sentiment & trending scores.
   137→ */
   138→class SentimentSpikeStrategy implements ScalingStrategy {
   139→  constructor(
   140→    private readonly meshClient: ServiceMeshClient,
   141→    private readonly threshold = 0.85,
   142→  ) {}
   143→
   144→  evaluate(metric: EnrichedMetric): ScalingCommand | undefined {
   145→    if (metric.trendingScore >= this.threshold && metric.sentimentScore > 0) {
   146→      // For viral events we aggressively over-provision.
   147→      return new ScaleUpCommand(this.meshClient, metric.appId, 3);
   148→    }
   149→    return undefined;
   150→  }
   151→}
   152→
   153→/* -------------------------------------------------------------------------- */
   154→/*                          Chain-of-Responsibility Layer                     */
   155→/* -------------------------------------------------------------------------- */
   156→
   157→interface AlertHandler {
   158→  setNext(handler: AlertHandler): AlertHandler;
   159→  handle(metric: EnrichedMetric): Promise<void>;
   160→}
   161→
   162→abstract class BaseAlertHandler implements AlertHandler {
   163→  private nextHandler?: AlertHandler;
   164→
   165→  public setNext(handler: AlertHandler): AlertHandler {
   166→    this.nextHandler = handler;
   167→    return handler;
   168→  }
   169→
   170→  public async handle(metric: EnrichedMetric): Promise<void> {
   171→    if (this.nextHandler) {
   172→      await this.nextHandler.handle(metric);
   173→    }
   174→  }
   175→}
   176→
   177→/** Debug-level handler – just noisy logs in dev environments. */
   178→class DebugAlertHandler extends BaseAlertHandler {
   179→  async handle(metric: EnrichedMetric): Promise<void> {
   180→    if (process.env.NODE_ENV !== 'production') {
   181→      console.debug(
   182→        `[DEBUG] Metric → cpu:${metric.cpuPct}% mem:${metric.memPct}% ` +
   183→        `sentiment:${metric.sentimentScore.toFixed(2)} trending:${metric.trendingScore}`,
   184→      );
   185→    }
   186→    await super.handle(metric);
   187→  }
   188→}
