    63→/* ============================================================================
    64→ *  Correlation Strategy Pattern
    65→ * ========================================================================== */
    66→
    67→export interface CorrelationStrategy {
    68→    /**
    69→     * Computes a correlation score between a metric and a social signal.
    70→     * Return in the inclusive range [0, 1].
    71→     *
    72→     * Returning NaN signals “unable to correlate”.
    73→     */
    74→    compute(
    75→        metric: SystemMetricEvent,
    76→        signal: SocialSignalEvent | null
    77→    ): number;
    78→}
    79→
    80→/**
    81→ * Default implementation that gives higher weight to memory/cpu spikes during high
    82→ * magnitude social events.
    83→ */
    84→export class WeightedCorrelationStrategy implements CorrelationStrategy {
    85→    compute(
    86→        metric: SystemMetricEvent,
    87→        signal: SocialSignalEvent | null
    88→    ): number {
    89→        if (!signal) return 0;
    90→
    91→        const metricFactor =
    92→            metric.metric.startsWith('cpu') || metric.metric.startsWith('memory')
    93→                ? 0.6
    94→                : 0.4;
    95→
    96→        // Normalise values: naive min-max assumption for demo purposes.
    97→        const normalisedMetric = Math.min(metric.value / 100, 1); // e.g. 90% CPU = 0.9
    98→        const normalisedSocial = Math.min(signal.magnitude / 10_000, 1);
    99→
   100→        const score = metricFactor * normalisedMetric + (1 - metricFactor) * normalisedSocial;
   101→
   102→        return Number.isNaN(score) ? 0 : Math.min(score, 1);
   103→    }
   104→}
