     2→/**************************************************************************************************
     3→ * File:        src/module_2.ts
     4→ * Project:     PulseSphere SocialOps (system_monitoring)
     5→ * Description: Telemetry processing pipeline that enriches incoming infrastructure metrics with
     6→ *              social-context signals (likes, comments, shares) and decides—via Strategy &
     7→ *              Chain-of-Responsibility patterns—whether to orchestrate proactive capacity
     8→ *              adjustments. The module exposes a self-contained `TelemetryProcessor` that can be
     9→ *              wired into any event-driven transport (Kafka/NATS/HTTP) and notifies downstream
    10→ *              observers when a scaling decision has been reached.
    11→ *
    12→ * Architectural patterns demonstrated:
    13→ *   • Observer                  – EventEmitter-based subscription to processed telemetry
    14→ *   • Chain-of-Responsibility   – Sequential handlers (validate → surge-detect → scale)
    15→ *   • Strategy                  – Pluggable scaling algorithms (aggressive, conservative, noop)
    16→ *
    17→ * NOTE: This file purposefully avoids external framework bindings (NestJS, Express, etc.) to keep
    18→ *       it transport-agnostic and easily testable. Integrations are expected to wrap the public
    19→ *       `TelemetryProcessor` methods.
    20→ **************************************************************************************************/
    21→
    22→import { EventEmitter } from 'events';
    23→import { createLogger, format, transports, Logger } from 'winston';
    24→
    25→// ────────────────────────────────────────────────────────────────────────────
    26→//  Domain Types
    27→// ────────────────────────────────────────────────────────────────────────────
    28→
    29→/**
    30→ * Represents an incoming telemetry datapoint produced by a system-metrics collector
    31→ * and already enriched with social-engagement metadata upstream.
    32→ */
    33→export interface TelemetryEvent {
    34→    metricName: string;                         // e.g. "api.requests_per_sec"
    35→    value: number;                              // numeric datapoint
    36→    timestamp: number;                          // epoch millis
    37→    /** Social context signals harvested via the PulseSphere mesh sidecar */
    38→    socialSignals: {
    39→        likes: number;
    40→        comments: number;
    41→        shares: number;
    42→        liveViewers: number;
    43→    };
    44→    /** Additional freeform metadata */
    45→    meta?: Record<string, unknown>;
    46→}
    47→
    48→/** Lightweight DTO emitted when a scaling request has been decided */
    49→export interface ScalingCommand {
    50→    readonly clusterId: string;
    51→    readonly desiredReplicas: number;
    52→    readonly reason: string;
    53→    readonly issuedAt: number;
    54→}
    55→
    56→// ────────────────────────────────────────────────────────────────────────────
    57→//  Observer Pattern
    58→// ────────────────────────────────────────────────────────────────────────────
    59→
    60→/**
    61→ * Centralised broadcaster for processed events. Other bounded contexts (alerting,
    62→ * deployment-automation, etc.) can listen to high-level signals without tight coupling.
    63→ */
    64→export class TelemetrySubject extends EventEmitter {
    65→    static readonly EVENTS = {
    66→        SCALING_NEEDED: 'scaling_needed',
    67→        EVENT_REJECTED: 'event_rejected',
    68→    } as const;
    69→}
    70→
    71→// ────────────────────────────────────────────────────────────────────────────
    72→//  Chain-of-Responsibility (abstract handler)
    73→// ────────────────────────────────────────────────────────────────────────────
    74→
    75→/**
    76→ * Base class for pipeline handlers. Each handler can decide to END or FORWARD the
    77→ * processing. Errors bubble upward and are logged once by the pipeline coordinator.
    78→ */
    79→abstract class Handler {
    80→    protected next?: Handler;
    81→
    82→    constructor(protected readonly logger: Logger) {}
    83→
    84→    setNext(handler: Handler): Handler {
    85→        this.next = handler;
    86→        return handler;
    87→    }
    88→
    89→    async handle(event: TelemetryEvent, subject: TelemetrySubject): Promise<void> {
    90→        const shouldContinue = await this.process(event, subject);
    91→        if (shouldContinue && this.next) {
    92→            return this.next.handle(event, subject);
    93→        }
    94→    }
    95→
    96→    /**
    97→     * @returns true  → forward event to next handler
    98→     *          false → stop chain propagation
    99→     */
   100→    protected abstract process(
   101→        event: TelemetryEvent,
   102→        subject: TelemetrySubject,
   103→    ): Promise<boolean>;
   104→}
   105→
   106→// ────────────────────────────────────────────────────────────────────────────
   107→//  Concrete Handlers
   108→// ────────────────────────────────────────────────────────────────────────────
   109→
   110→/**
   111→ * Performs basic schema & sanity checks. Rejects obviously corrupt data early.
   112→ */
   113→class ValidationHandler extends Handler {
   114→    private static readonly REQUIRED_FIELDS: (keyof TelemetryEvent)[] = [
   115→        'metricName',
   116→        'value',
   117→        'timestamp',
   118→        'socialSignals',
   119→    ];
   120→
   121→    protected async process(event: TelemetryEvent, subject: TelemetrySubject): Promise<boolean> {
   122→        for (const field of ValidationHandler.REQUIRED_FIELDS) {
   123→            if (event[field] === undefined || event[field] === null) {
   124→                this.logger.warn(`Telemetry event missing required field "${field}"`, { event });
   125→                subject.emit(TelemetrySubject.EVENTS.EVENT_REJECTED, {
   126→                    reason: `Missing field: ${field}`,
   127→                    event,
   128→                });
   129→                return false; // stop chain
   130→            }
   131→        }
   132→        return true;
   133→    }
   134→}
   135→
   136→/**
   137→ * Detects social-driven surges (likes, shares, etc.) that may soon overload
   138→ * infrastructure. If a surge is not detected, the chain stops here.
   139→ */
   140→class SurgeDetectionHandler extends Handler {
   141→    private readonly likeThreshold: number;
   142→    private readonly shareThreshold: number;
   143→    private readonly liveViewerThreshold: number;
   144→
   145→    constructor(logger: Logger, cfg?: { like?: number; share?: number; live?: number }) {
   146→        super(logger);
   147→        this.likeThreshold = cfg?.like ?? 1_000;
   148→        this.shareThreshold = cfg?.share ?? 500;
   149→        this.liveViewerThreshold = cfg?.live ?? 10_000;
   150→    }
   151→
   152→    protected async process(event: TelemetryEvent): Promise<boolean> {
   153→        const signals = event.socialSignals;
   154→        const surgeDetected =
   155→            signals.likes >= this.likeThreshold ||
   156→            signals.shares >= this.shareThreshold ||
   157→            signals.liveViewers >= this.liveViewerThreshold;
   158→
   159→        if (!surgeDetected) {
   160→            this.logger.debug('No social surge detected, skipping scaling.', {
   161→                metric: event.metricName,
   162→                signals,
   163→            });
   164→            // Do NOT continue the chain – no scaling required
   165→            return false;
   166→        }
   167→
   168→        this.logger.info('Social surge detected.', {
   169→            metric: event.metricName,
   170→            signals,
   171→        });
   172→        return true; // continue to scaling handler
   173→    }
   174→}
   175→
   176→// ────────────────────────────────────────────────────────────────────────────
   177→//  Strategy Pattern for scaling algorithms
   178→// ────────────────────────────────────────────────────────────────────────────
   179→
   180→export interface ScalingStrategy {
   181→    /**
   182→     * Calculates how many replicas are needed to sustain observed load.
   183→     *
   184→     * @param currentReplicas Current number of replicas in the cluster
   185→     * @param event           Event responsible for triggering scaling evaluation
   186→     */
   187→    computeDesiredReplicas(currentReplicas: number, event: TelemetryEvent): number;
   188→}
   189→
   190→class AggressiveScalingStrategy implements ScalingStrategy {
   191→    computeDesiredReplicas(currentReplicas: number, event: TelemetryEvent): number {
   192→        // Scale up quickly: +50% replicas per detection
   193→        return Math.ceil(currentReplicas * 1.5);
   194→    }
   195→}
   196→
   197→class ConservativeScalingStrategy implements ScalingStrategy {
   198→    computeDesiredReplicas(currentReplicas: number, event: TelemetryEvent): number {
   199→        // Step scaling: +1 replica at a time (bounded)
   200→        return currentReplicas + 1;
   201→    }
   202→}
   203→
   204→class NoopScalingStrategy implements ScalingStrategy {
   205→    computeDesiredReplicas(currentReplicas: number): number {
   206→        return currentReplicas; // no scaling
   207→    }
   208→}
   209→
   210→// ────────────────────────────────────────────────────────────────────────────
   211→//  Scaling Handler (end of chain)
   212→// ────────────────────────────────────────────────────────────────────────────
   213→
   214→class ScalingDecisionHandler extends Handler {
   215→    private readonly strategy: ScalingStrategy;
   216→    private readonly clusterIdResolver: (event: TelemetryEvent) => string;
   217→    private readonly minReplicas: number;
   218→    private readonly maxReplicas: number;
   219→
   220→    constructor(
   221→        logger: Logger,
   222→        cfg: {
   223→            strategy: ScalingStrategy;
   224→            clusterIdResolver?: (event: TelemetryEvent) => string;
   225→            minReplicas?: number;
   226→            maxReplicas?: number;
   227→        },
   228→    ) {
   229→        super(logger);
   230→        this.strategy = cfg.strategy;
   231→        this.clusterIdResolver = cfg.clusterIdResolver ?? (() => 'default-cluster');
   232→        this.minReplicas = cfg.minReplicas ?? 1;
   233→        this.maxReplicas = cfg.maxReplicas ?? 1_000;
   234→    }
   235→
   236→    protected async process(event: TelemetryEvent, subject: TelemetrySubject): Promise<boolean> {
   237→        const clusterId = this.clusterIdResolver(event);
   238→        const currentReplicas = this.resolveCurrentReplicas(clusterId);
   239→
   240→        const desired = this.strategy.computeDesiredReplicas(currentReplicas, event);
   241→        const boundedDesired = Math.max(this.minReplicas, Math.min(this.maxReplicas, desired));
   242→
   243→        if (boundedDesired === currentReplicas) {
   244→            this.logger.info('Scaling evaluation resulted in no changes.', { clusterId });
   245→            return false; // chain ends
   246→        }
   247→
   248→        const cmd: ScalingCommand = {
   249→            clusterId,
   250→            desiredReplicas: boundedDesired,
   251→            reason: 'social-surge',
   252→            issuedAt: Date.now(),
   253→        };
   254→
   255→        this.logger.info('Emitting scaling command.', cmd);
   256→        subject.emit(TelemetrySubject.EVENTS.SCALING_NEEDED, cmd);
   257→        return false; // end of chain
   258→    }
   259→
   260→    /** Placeholder: in real life we'd query Kubernetes-API, Nomad, etc. */
   261→    private resolveCurrentReplicas(_clusterId: string): number {
   262→        return 3; // mock value for demo purposes
   263→    }
   264→}
   265→
   266→// ────────────────────────────────────────────────────────────────────────────
   267→//  Public API – TelemetryProcessor
   268→// ────────────────────────────────────────────────────────────────────────────
   269→
   270→export interface TelemetryProcessorOptions {
   271→    scalingStrategy?: 'aggressive' | 'conservative' | 'noop';
   272→    validation?: { like?: number; share?: number; live?: number };
   273→    minReplicas?: number;
   274→    maxReplicas?: number;
   275→}
   276→
   277→/**
   278→ * Exposes a high-level facade to process telemetry events. Downstream consumers
   279→ * may subscribe to the `subject` property to react to scaling decisions.
   280→ */
   281→export class TelemetryProcessor {
   282→    /** Observer subject for external consumers */
   283→    public readonly subject = new TelemetrySubject();
   284→
   285→    private readonly logger: Logger;
   286→    private readonly pipeline: Handler;
   287→
   288→    constructor(private readonly opts: TelemetryProcessorOptions = {}) {
   289→        // Create namespaced logger
   290→        this.logger = createLogger({
   291→            level: process.env.PS_LOG_LEVEL || 'info',
   292→            format: format.combine(
   293→                format.timestamp(),
   294→                format.errors({ stack: true }),
   295→                format.splat(),
   296→                format.json(),
   297→            ),
   298→            transports: [new transports.Console()],
   299→            defaultMeta: { service: 'telemetry-processor' },
   300→        });
   301→
   302→        // Build handler chain
   303→        const validator = new ValidationHandler(this.logger);
   304→        const surgeDetector = new SurgeDetectionHandler(this.logger, opts.validation);
   305→        const scaler = new ScalingDecisionHandler(this.logger, {
   306→            strategy: TelemetryProcessor.selectStrategy(opts.scalingStrategy),
   307→            minReplicas: opts.minReplicas,
   308→            maxReplicas: opts.maxReplicas,
   309→        });
   310→
   311→        validator.setNext(surgeDetector).setNext(scaler);
   312→        this.pipeline = validator;
   313→    }
   314→
   315→    /**
   316→     * Entry-point for new telemetry events.
   317→     */
   318→    async ingest(event: TelemetryEvent): Promise<void> {
   319→        try {
   320→            await this.pipeline.handle(event, this.subject);
   321→        } catch (err) {
   322→            this.logger.error('Unhandled error in telemetry pipeline', { err, event });
