     2→/***************************************************************************************************
     3→ *  PulseSphere SocialOps – Adaptive Capacity Orchestrator
     4→ *  -----------------------------------------------------------------------------------------------
     5→ *  File:          src/module_10.ts
     6→ *  Responsibility: Listen to infrastructure metrics _and_ social-engagement signals, correlate
     7→ *                  them in near-real-time and issue scale-up / scale-down commands to the cluster
     8→ *                  control-plane before virality spikes impact SLOs.
     9→ *
    10→ *  Architectural patterns used:
    11→ *    • Observer Pattern      – RxJS streams wrap Kafka/NATS topics.
    12→ *    • Strategy Pattern      – Pluggable scaling strategies.
    13→ *    • Chain of Responsibility – Post-decision handlers (dry-run, dispatch, notify).
    14→ *    • Command Pattern       – Encapsulate calls to the Cluster Manager API.
    15→ *
    16→ *  External deps (peer deps declared in package.json):
    17→ *    "@types/node", "kafkajs", "nats", "rxjs", "axios", "uuid"
    18→ ***************************************************************************************************/
    19→
    20→import axios, { AxiosInstance } from 'axios';
    21→import { Kafka, EachMessagePayload, logLevel } from 'kafkajs';
    22→import { connect, JSONCodec, NatsConnection, Subscription } from 'nats';
    23→import { Subject, merge, Observable } from 'rxjs';
    24→import { bufferTime, filter, map, catchError } from 'rxjs/operators';
    25→import { v4 as uuid } from 'uuid';
    26→
    27→/* -------------------------------------------------------------------------------------------------
    28→ * Domain Models
    29→ * -----------------------------------------------------------------------------------------------*/
    30→interface InfraMetricEvent {
    31→  timestamp: number;               // epoch millis
    32→  clusterId: string;
    33→  avgCpu: number;                  // aggregated CPU util %
    34→  avgMem: number;                  // aggregated Mem util %
    35→}
    36→
    37→interface SocialSignalEvent {
    38→  timestamp: number;
    39→  userSegment: 'global' | 'region' | 'influencer';
    40→  magnitude: number;               // e.g. delta of likes/min or new live viewers
    41→  cause?: string;                  // optional hashtag / campaign identifier
    42→}
    43→
    44→interface AggregatedSignal {
    45→  timestamp: number;
    46→  windowMs: number;
    47→  clusterId: string;
    48→  avgCpu: number;
    49→  avgMem: number;
    50→  socialMagnitude: number;
    51→}
    52→
    53→enum ScaleDirection {
    54→  SCALE_OUT = 'SCALE_OUT',
    55→  SCALE_IN = 'SCALE_IN',
    56→  NONE = 'NONE'
    57→}
    58→
    59→interface ScaleDecision {
    60→  id: string;
    61→  timestamp: number;
    62→  direction: ScaleDirection;
    63→  amount: number;                  // positive integer representing # replicas to add/remove
    64→  reason: string;
    65→  dryRun?: boolean;
    66→}
    67→
    68→/* -------------------------------------------------------------------------------------------------
    69→ * Configuration
    70→ * -----------------------------------------------------------------------------------------------*/
    71→const CONFIG = {
    72→  KAFKA_BROKERS: process.env.KAFKA_BROKERS?.split(',') ?? ['kafka:9092'],
    73→  NATS_URL: process.env.NATS_URL ?? 'nats://nats:4222',
    74→  OBSERVABILITY_WINDOW_MS: 5_000,
    75→  SOCIAL_MAGNITUDE_THRESHOLD: 500,
    76→  CPU_SCALE_OUT_THRESHOLD: 0.70,
    77→  CPU_SCALE_IN_THRESHOLD: 0.25,
    78→  MAX_REPLICAS_DELTA: 25,
    79→  CLUSTER_MANAGER_BASE_URL: process.env.CLUSTER_MANAGER_URL ?? 'http://cluster-mgr.svc',
    80→  DRY_RUN: process.env.DRY_RUN === 'true',
    81→  LOG_LEVEL: process.env.LOG_LEVEL ?? 'info'
    82→};
    83→
    84→/* -------------------------------------------------------------------------------------------------
    85→ * Observer – Event Buses
    86→ * -----------------------------------------------------------------------------------------------*/
    87→
    88→/**
    89→ * MetricBus and SocialBus are RxJS Subjects that act as hot observable streams for downstream
    90→ * consumers.
    91→ */
    92→const metricBus = new Subject<InfraMetricEvent>();
    93→const socialBus = new Subject<SocialSignalEvent>();
    94→
    95→/**
    96→ * Consolidated view – merge metric & social streams, then buffer them in sliding window.
    97→ */
    98→const aggregatedStream: Observable<AggregatedSignal[]> = merge(metricBus, socialBus).pipe(
    99→  bufferTime(CONFIG.OBSERVABILITY_WINDOW_MS),
   100→  // Filter out empty windows
   101→  filter(events => events.length > 0),
   102→  map(events => {
   103→    // Simple aggregation; in production we would use more robust windowing (e.g. Kafka Streams)
   104→    const metrics = events.filter((e): e is InfraMetricEvent => (e as InfraMetricEvent).avgCpu !== undefined);
   105→    const social = events.filter((e): e is SocialSignalEvent => (e as SocialSignalEvent).magnitude !== undefined);
   106→
   107→    const clusterId = metrics.length ? metrics[0].clusterId : 'global';
   108→
   109→    const avgCpu = metrics.reduce((sum, m) => sum + m.avgCpu, 0) / (metrics.length || 1);
   110→    const avgMem = metrics.reduce((sum, m) => sum + m.avgMem, 0) / (metrics.length || 1);
   111→    const socialMagnitude = social.reduce((sum, s) => sum + s.magnitude, 0);
   112→
   113→    return [{
   114→      timestamp: Date.now(),
   115→      windowMs: CONFIG.OBSERVABILITY_WINDOW_MS,
   116→      clusterId,
   117→      avgCpu,
   118→      avgMem,
   119→      socialMagnitude
   120→    }];
   121→  })
   122→);
   123→
   124→/* -------------------------------------------------------------------------------------------------
   125→ * Strategy Pattern – Scaling Decision Strategies
   126→ * -----------------------------------------------------------------------------------------------*/
   127→interface ScalingStrategy {
   128→  /**
   129→   * Inspect aggregated signal and decide whether to scale.
   130→   * Returns a ScaleDecision or undefined if no action required.
   131→   */
   132→  evaluate(signal: AggregatedSignal): ScaleDecision | undefined;
   133→}
   134→
   135→/**
   136→ * CPU-based auto-scaling strategy
   137→ */
   138→class CpuBasedScalingStrategy implements ScalingStrategy {
   139→  evaluate(signal: AggregatedSignal): ScaleDecision | undefined {
   140→    if (signal.avgCpu > CONFIG.CPU_SCALE_OUT_THRESHOLD) {
   141→      const delta = Math.min(
   142→        Math.ceil((signal.avgCpu - CONFIG.CPU_SCALE_OUT_THRESHOLD) * 100),
   143→        CONFIG.MAX_REPLICAS_DELTA
   144→      );
   145→
   146→      return {
   147→        id: uuid(),
   148→        timestamp: Date.now(),
   149→        direction: ScaleDirection.SCALE_OUT,
   150→        amount: delta,
   151→        reason: `Avg CPU high (${(signal.avgCpu * 100).toFixed(1)}%)`
   152→      };
   153→    }
   154→
   155→    if (signal.avgCpu < CONFIG.CPU_SCALE_IN_THRESHOLD) {
   156→      const delta = Math.min(
   157→        Math.ceil((CONFIG.CPU_SCALE_IN_THRESHOLD - signal.avgCpu) * 100),
   158→        CONFIG.MAX_REPLICAS_DELTA
   159→      );
   160→      return {
   161→        id: uuid(),
   162→        timestamp: Date.now(),
   163→        direction: ScaleDirection.SCALE_IN,
   164→        amount: delta,
   165→        reason: `Avg CPU low (${(signal.avgCpu * 100).toFixed(1)}%)`
   166→      };
   167→    }
   168→
   169→    return undefined;
   170→  }
   171→}
   172→
   173→/**
   174→ * Social-surge scaling strategy – reacts to sudden increases in social activity
   175→ */
   176→class SocialSurgeScalingStrategy implements ScalingStrategy {
   177→  evaluate(signal: AggregatedSignal): ScaleDecision | undefined {
   178→    if (signal.socialMagnitude >= CONFIG.SOCIAL_MAGNITUDE_THRESHOLD) {
   179→      const delta = Math.min(
   180→        Math.ceil(signal.socialMagnitude / CONFIG.SOCIAL_MAGNITUDE_THRESHOLD),
   181→        CONFIG.MAX_REPLICAS_DELTA
   182→      );
   183→
   184→      return {
   185→        id: uuid(),
   186→        timestamp: Date.now(),
   187→        direction: ScaleDirection.SCALE_OUT,
   188→        amount: delta,
   189→        reason: `Social magnitude spike (${signal.socialMagnitude})`
   190→      };
   191→    }
   192→    return undefined;
   193→  }
   194→}
   195→
   196→/* -------------------------------------------------------------------------------------------------
   197→ * Command Pattern – Cluster Scaling Command
   198→ * -----------------------------------------------------------------------------------------------*/
   199→class ScaleCommand {
   200→  constructor(
   201→    private readonly decision: ScaleDecision,
   202→    private readonly apiClient: AxiosInstance
   203→  ) {}
   204→
   205→  async execute(): Promise<void> {
   206→    const { direction, amount } = this.decision;
   207→    const verb = direction === ScaleDirection.SCALE_IN ? 'scale-in' : 'scale-out';
   208→    const url = `/clusters/default/${verb}`;
   209→
   210→    try {
   211→      await this.apiClient.post(url, { replicas: amount, meta: { id: this.decision.id } });
   212→      Logger.info(`[CMD] Successfully executed ${verb} x${amount}`);
   213→    } catch (err) {
   214→      Logger.error(`[CMD] Failed to execute ${verb}:`, err);
   215→      throw err;
   216→    }
   217→  }
   218→}
   219→
   220→/* -------------------------------------------------------------------------------------------------
   221→ * Chain of Responsibility – Decision Handlers
   222→ * -----------------------------------------------------------------------------------------------*/
   223→interface DecisionHandler {
   224→  setNext(handler: DecisionHandler): DecisionHandler;
   225→  handle(decision: ScaleDecision): Promise<void>;
   226→}
   227→
   228→abstract class AbstractDecisionHandler implements DecisionHandler {
   229→  private nextHandler?: DecisionHandler;
