### 1. Event Bus Definition (Core Pub/Sub Pattern)
```typescript
// File: /app/project/src/module_32.ts
// Lines: 182-198

/**
 * Internal EventBus abstraction.  In production we delegate to Kafka or NATS
 * but for local dev / unit testing an EventEmitter is sufficient.
 */
export class EventBus extends EventEmitter {
  publish<T>(topic: string, payload: T) {
    this.emit(topic, payload);
  }

  subscribe<T>(
    topic: string,
    listener: (payload: T) => void
  ): () => void /* unsubscribe */ {
    this.on(topic, listener);
    return () => this.off(topic, listener);
  }
}
```

### 2. Configuration Management with Hot-Reload
```typescript
// File: /app/project/src/module_36.ts
// Lines: 83-102

export class ConfigManager extends EventEmitter {
    private current: AlertingEngineConfig;

    constructor(defaults: AlertingEngineConfig) {
        super();
        this.current = defaults;
    }

    get(): AlertingEngineConfig {
        return { ...this.current };
    }

    /**
     * Hot-reloads current configuration and notifies listeners
     */
    update(newConfig: Partial<AlertingEngineConfig>): void {
        this.current = { ...this.current, ...newConfig };
        this.emit('update', this.get());
    }
}
```

### 3. Validation Step (Chain-of-Responsibility)
```typescript
// File: /app/project/src/module_42.ts
// Lines: 211-230

class ValidationStep extends AbstractStep {
  async handle({ message, topic, partition }: EachMessagePayload): Promise<void> {
    try {
      if (!message.value) throw new Error('Empty message');

      const raw = JSON.parse(message.value.toString());
      const parsed: RawMetric = RawMetricSchema.parse(raw);

      // Pass parsed object inside message headers for downstream steps
      message.headers = {
        ...message.headers,
        _parsedMetric: Buffer.from(JSON.stringify(parsed)),
      };
      await this.nextHandle({ message, topic, partition });
    } catch (err) {
      logger.error({ err }, 'Validation failure – routing to DLQ');
      await DLQPublisher.publish(message);
    }
  }
}
```

### 4. Persistence Step
```typescript
// File: /app/project/src/module_57.ts
// Lines: 161-174

class PersistenceStep implements PipelineStep {
    constructor(private readonly logger: winston.Logger) {}

    async handle(event: CorrelatedEvent, next: () => Promise<void>): Promise<void> {
        // In production we'd persist into ClickHouse / TimescaleDB or send to Kafka topic.
        try {
            this.logger.info('Persisting correlated event', { event });
        } catch (err) {
            this.logger.warn('Failed to persist correlated event', { err, event });
        }
        await next();
    }
}
```

### 5. Alert Correlation Engine (Metric Evaluation)
```typescript
// File: /app/project/src/module_4.ts
// Lines: 241-269

export class AlertCorrelationEngine {
  private readonly telemetry$ = new Subject<TelemetryEvent>();
  private currentStrategy: AlertCorrelationStrategy;

  constructor(private readonly options: EngineOptions) {
    // Bootstrap initial strategy
    const initialDescriptor = options.configService.get<StrategyDescriptor>(
      this.strategyConfigPath
    );
    this.currentStrategy = StrategyFactory.create(initialDescriptor);

    // Subscribe to config changes to hot-swap strategies
    options.configService
      .onChange(this.strategyConfigPath)
      .subscribe((newDescriptor) => this.updateStrategy(newDescriptor as StrategyDescriptor));

    // Wire telemetry stream
    options.telemetryStream$.subscribe({
      next: (ev) => this.telemetry$.next(ev),
      error: (err) => this.logger('Telemetry stream failure', err),
    });

    // Start pipeline
    this.initProcessingPipeline();
  }
}
```

